mapper.select:
select id, name, type, description, is_system, status, created_by, created_at, updated_by, updated_at
from project_template
where 1 = 1

    and type = #{type}


    and status = #{status}

order by created_at desc

select id, name, type, description, is_system, status, created_by, created_at, updated_by, updated_at
from project_template
where id = #{id}

mapper.insert:
insert into project_template (
    id, name, type, description, is_system, status, created_by, created_at, updated_by, updated_at
) values (
    #{id}, #{name}, #{type}, #{description}, #{isSystem}, #{status}, #{createdBy}, #{createdAt}, #{updatedBy}, #{updatedAt}
)
